Reproduce this
library(cybedtools)
library(dplyr)

framework_summary |&gt;
  group_by(jurisdiction) |&gt;
  summarise(
    frameworks = paste(framework_name, collapse = ", "),
    total_elements = sum(element_count_with_examples),
    .groups = "drop"
  ) |&gt;
  arrange(desc(total_elements))
The framework_summary tibble ships with the package as a lazy-loaded data object. Element totals are jurisdiction-attributed at the framework level via the jurisdiction column.

Reproduce this
library(cybedtools)
library(dplyr)

rdf &lt;- load_combined_ntriples_graph()

nice_role_counts &lt;- role_framework_bindings(rdf) |&gt;
  filter(grepl("^NICE", framework_name)) |&gt;
  inner_join(
    role_element_bindings(rdf) |&gt; count(role, name = "element_count"),
    by = "role"
  ) |&gt;
  arrange(desc(element_count)) |&gt;
  select(role_name, element_count)
The full prep script is in concordance/_data-prep-top-work-roles.R in the repository.
